mapper.update:
UPDATE event_battle_option o
INNER JOIN event_battle e ON e.event_battle_seq = o.event_battle_seq AND e.use_yn = 'Y'
SET o.points_total = o.points_total + #{delta}
WHERE o.event_battle_option_seq = #{eventBattleOptionSeq}
  AND e.status = 'OPEN'

mapper.delete:
DELETE FROM event_battle_vote
WHERE event_battle_seq = #{eventBattleSeq}
  AND member_seq = #{memberSeq}

mapper.select:
SELECT event_battle_option_seq
FROM event_battle_vote
WHERE event_battle_seq = #{eventBattleSeq}
  AND member_seq = #{memberSeq}
ORDER BY event_battle_option_seq ASC

SELECT b.event_battle_bet_seq AS eventBattleBetSeq, b.member_seq AS memberSeq, COALESCE(NULLIF(TRIM(m.NICKNAME), ''), NULLIF(TRIM(m.MEMBER_NAME), ''), m.MEMBER_ID) AS memberDisplayName, b.event_battle_option_seq AS eventBattleOptionSeq, o.label AS optionLabel, b.point_amount AS pointAmount, DATE_FORMAT(b.create_dt, '%Y-%m-%d %H:%i:%s') AS createDt FROM event_battle_bet b INNER JOIN member m ON m.member_seq = b.member_seq AND m.USE_YN = 'Y' INNER JOIN event_battle_option o ON o.event_battle_option_seq = b.event_battle_option_seq WHERE b.event_battle_seq = #{eventBattleSeq}
AND b.event_battle_bet_seq > #{sinceSeq}
ORDER BY b.event_battle_bet_seq DESC LIMIT #{limit}
